import { Injectable, NotFoundException } from '@nestjs/common';
import { Country, Device, Institution } from './models';
import { LookupDto } from './dto/lookup.dto';

@Injectable()
export class LookupsService {
  private countries: Country[] = [];
  private devices: Device[] = [];
  private institutions: Institution[] = [];

  constructor() {
    // Initialize with some default data
    this.countries = [{ id: 1, name: 'Country A' }, { id: 2, name: 'Country B' }];
    this.devices = [{ id: 1, name: 'Device A' }, { id: 2, name: 'Device B' }];
    this.institutions = [{ id: 1, name: 'Institution A' }, { id: 2, name: 'Institution B' }];
  }

  validateLookupDto(lookupDto: LookupDto) {
    if (!lookupDto || !lookupDto.type) {
      throw new Error('Invalid lookup type');
    }
  }

  getCountries(): Country[] {
    return this.countries;
  }

  getDevices(): Device[] {
    return this.devices;
  }

  getInstitutions(): Institution[] {
    return this.institutions;
  }

  lookup(lookupDto: LookupDto): Country | Device | Institution {
    this.validateLookupDto(lookupDto);

    switch (lookupDto.type) {
      case 'country':
        const country = this.countries.find(c => c.id === lookupDto.id);
        if (!country) throw new NotFoundException('Country not found');
        return country;

      case 'device':
        const device = this.devices.find(d => d.id === lookupDto.id);
        if (!device) throw new NotFoundException('Device not found');
        return device;

      case 'institution':
        const institution = this.institutions.find(i => i.id === lookupDto.id);
        if (!institution) throw new NotFoundException('Institution not found');
        return institution;

      default:
        throw new Error('Invalid lookup type');
    }
  }
}
